            if (balanceAccountConfiguration._RetainedAmountOption.IsSet)
                if (balanceAccountConfiguration._RetainedAmountOption.Value != null)
                    writer.WriteNumber("retainedAmount", balanceAccountConfiguration._RetainedAmountOption.Value!.Value);

            if (balanceAccountConfiguration._SalesDayClosingTimeOption.IsSet)
                if (balanceAccountConfiguration.SalesDayClosingTime != null)
                    writer.WriteString("salesDayClosingTime", balanceAccountConfiguration.SalesDayClosingTime);

            if (balanceAccountConfiguration._UpdatedAtOption.IsSet)
                if (balanceAccountConfiguration._UpdatedAtOption.Value != null)
                    writer.WriteString("updatedAt", balanceAccountConfiguration._UpdatedAtOption.Value!.Value.ToString(UpdatedAtFormat));
        }
    }
}
